'use client';

import { useState } from 'react';
import { trpc } from '@/lib/trpc-client';
import Image from 'next/image';

export default function Home() {
  const [file, setFile] = useState<File | null>(null);
  const [uploadedUrl, setUploadedUrl] = useState<string | null>(null);

  const uploadMutation = trpc.uploadFile.useMutation({
    onSuccess: (data) => {
      setUploadedUrl(data.url);
      setFile(null);
    },
    onError: (error) => {
      alert(`Upload failed: ${error.message}`);
    },
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file) return;

    const formData = new FormData();
    formData.append('file', file);

    uploadMutation.mutate(formData);
  };

  return (
    <main className="flex flex-col items-center justify-center min-h-screen p-24">
      <div className="z-10 max-w-5xl w-full items-center justify-between font-mono text-sm">
        <h1 className="text-4xl font-bold mb-8 text-center">tRPC v11 File Upload</h1>

        <form onSubmit={handleSubmit} className="flex flex-col items-center space-y-4 bg-white p-8 rounded-lg shadow-md text-black">
          <div className="flex flex-col space-y-2 w-full">
            <label htmlFor="file" className="font-semibold text-gray-700">Select Image</label>
            <input
              id="file"
              type="file"
              accept="image/*"
              onChange={(e) => setFile(e.target.files?.[0] || null)}
              className="block w-full text-sm text-gray-500
                file:mr-4 file:py-2 file:px-4
                file:rounded-full file:border-0
                file:text-sm file:font-semibold
                file:bg-blue-50 file:text-blue-700
                hover:file:bg-blue-100"
            />
          </div>

          <button
            type="submit"
            disabled={!file || uploadMutation.isPending}
            className="w-full bg-blue-600 text-white py-2 px-4 rounded-md font-medium hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-colors"
          >
            {uploadMutation.isPending ? 'Uploading...' : 'Upload File'}
          </button>
        </form>

        {uploadedUrl && (
          <div className="mt-12 flex flex-col items-center">
            <h2 className="text-2xl font-semibold mb-4">Uploaded Successfully!</h2>
            <div className="relative w-64 h-64 border-2 border-gray-300 rounded-lg overflow-hidden">
              <Image
                src={uploadedUrl}
                alt="Uploaded file"
                fill
                className="object-contain"
              />
            </div>
            <p className="mt-4 text-gray-600">URL: {uploadedUrl}</p>
          </div>
        )}
      </div>
    </main>
  );
}

